import 'package:flutter/material.dart';
import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

class BiometricAuth {
  static final LocalAuthentication auth = LocalAuthentication();
  static final SharedPreferences prefs = SharedPreferences.getInstance();

  static Future<bool> authenticate() async {
    try {
      final bool canCheckBiometrics = await auth.canCheckBiometrics;
      if (!canCheckBiometrics) {
        return false;
      }

      final List<BiometricType> availableBiometrics = await auth.getAvailableBiometrics();
      if (availableBiometrics.isEmpty) {
        return false;
      }

      final bool authenticated = await auth.authenticate(
        localizedReason: 'Please authenticate to access the app',
        options: const AuthenticationOptions(
          stickyAuth: true,
          biometricOnly: true,
        ),
      );

      if (authenticated) {
        await prefs.setBool('biometric_authenticated', true);
        return true;
      }
    } catch (e) {
      print('Authentication error: $e');
    }
    return false;
  }

  static Future<bool> isBiometricAuthenticated() async {
    final bool? isAuthenticated = prefs.getBool('biometric_authenticated');
    return isAuthenticated ?? false;
  }

  static Future<void> clearBiometricAuth() async {
    await prefs.setBool('biometric_authenticated', false);
  }
}

